Trace the loading, error, and success flow in this component. What does the user see at each stage when they select a different category?

```jsx
function CategoryProducts({ categoryId }) {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    setLoading(true);
    setError(null);

    fetch(`/api/categories/${categoryId}/products`)
      .then(res => {
        if (!res.ok) throw new Error('Failed to load products');
        return res.json();
      })
      .then(data => {
        setProducts(data);
        setLoading(false);
      })
      .catch(err => {
        setError(err.message);
        setLoading(false);
      });
  }, [categoryId]);

  if (loading) return <div className="skeleton-grid" />;
  if (error) return <ErrorBanner message={error} />;

  return (
    <div className="product-grid">
      {products.map(p => (
        <ProductCard key={p.id} product={p} />
      ))}
    </div>
  );
}
```

A client reports: "When I submit the feedback form, the page refreshes and my message is lost." Find the bug.

```jsx
function FeedbackForm() {
  const [rating, setRating] = useState(5);
  const [comment, setComment] = useState('');
  const [submitted, setSubmitted] = useState(false);

  async function handleSubmit(e) {
    const res = await fetch('/api/feedback', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ rating, comment }),
    });
    if (res.ok) setSubmitted(true);
  }

  if (submitted) return <p>Thank you for your feedback!</p>;

  return (
    <form onSubmit={handleSubmit}>
      <select value={rating} onChange={e => setRating(Number(e.target.value))}>
        {[1,2,3,4,5].map(n => <option key={n} value={n}>{n} stars</option>)}
      </select>
      <textarea
        value={comment}
        onChange={e => setComment(e.target.value)}
        placeholder="Your feedback..."
      />
      <button type="submit">Submit</button>
    </form>
  );
}
```

You are reviewing AI-generated code for a comment section. The client says: "Posting a comment works, but it takes 2 seconds before my comment appears in the list. It feels broken." The AI used a standard fetch-then-reload approach. What pattern would you suggest to make it feel instant, and what would you tell the AI?

```jsx
function CommentSection({ postId }) {
  const [comments, setComments] = useState([]);
  const [newComment, setNewComment] = useState('');

  useEffect(() => {
    fetch(`/api/posts/${postId}/comments`)
      .then(res => res.json())
      .then(data => setComments(data));
  }, [postId]);

  async function handleSubmit(e) {
    e.preventDefault();
    await fetch(`/api/posts/${postId}/comments`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ text: newComment }),
    });
    // Re-fetch all comments after posting
    const res = await fetch(`/api/posts/${postId}/comments`);
    const data = await res.json();
    setComments(data);
    setNewComment('');
  }

  return (
    <div>
      {comments.map(c => <p key={c.id}>{c.text}</p>)}
      <form onSubmit={handleSubmit}>
        <textarea
          value={newComment}
          onChange={e => setNewComment(e.target.value)}
        />
        <button type="submit">Post Comment</button>
      </form>
    </div>
  );
}
```

